trigger.body:
    vStatus VARCHAR2(60);
BEGIN
	IF DELETING THEN
        select Status into vStatus from sspitra_collectiontransit where sspitra_collectiontransit_id = :OLD.sspitra_collectiontransit_id;
        IF vStatus = 'P' THEN
    		RAISE_APPLICATION_ERROR(-20000, '@SSPITRA_ActionNotAllowed@');
        END IF;
	END IF;

END SSPITRA_CT_DETAIL_BEFORE_TRG
